  ('generalpolice-94737317-moex-00552', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依司法院大法官解釋意旨，關於憲法第7條之規定，下列敘述何者正確？', '["保障主體僅限於「中華民國人民」，故其屬國民權之類型", "於法律明文規定之範圍內，法人得主張平等權", "在本質上合適之範圍內，法人亦得主張平等權", "非中華民國人民是否得主張平等權，應適用互惠原則進一步加以判斷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00553', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '關於憲法增修條文中立法院與總統間關係之規定，下列敘述何者錯誤？', '["立法院每年集會時，得聽取總統國情報告", "總統有解散立法院之權限", "總統、副總統之彈劾案，經全體立法委員四分之一以上之提議，全體立法委員三分之二以上之決 議，被彈劾人應即解職", "總統發布之緊急命令須提交立法院追認，如立法院不同意時，該緊急命令立即失效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00554', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依司法院大法官解釋，關於專門職業及技術人員，下列敘述何者錯誤？', '["專門職業及技術人員執業資格，應經考試院依法考選銓定", "某項職業屬於專門職業之認定，應以法律定之", "關於某項職業是否為專門職業之認定，立法機關有完全形成自由", "專門職業及技術人員應具備經由現代教育或訓練之培養過程所獲得之特殊學識或技能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00555', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依憲法增修條文規定，有關司法院大法官之任命與地位，下列敘述何者正確？', '["總統提名經監察院同意後任命", "除院長與副院長外，另有大法官15人", "任期8年，不得連任", "大法官為法官，享有憲法第81條規定之終身職待遇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00556', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依司法院大法官解釋，以下何項差別待遇，並不適用較為嚴格的審查標準？', '["人民因未具特定教育體系學歷，而無法取得擔任高階公務人員職務資格之差別待遇", "人民因為婚姻關係的有無，而負擔不同租稅義務", "勞基法與公務人員退休法對退休金請求權得否扣押或供擔保，定有不同的規範", "受長期照護者的醫療費用，限由特定醫療院所開立之證明始得申報扣除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
