  ('generalpolice-94737317-moex-00558', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依司法院釋字第 469 號解釋之意旨，公務員怠於執行職務而成立之國家賠償責任，不包括下列那一個要 件？', '["法律之目的係為保護人民生命、身體及財產等法益", "公務員之違法行為與人民之損害間，有相當因果關係", "須法律明文賦予人民有特定職務行為之公法上請求權", "公務員對於特定人有作為義務，並無不作為之空間"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
